bomData.valueScript:
// Type of the Bom-Element (will be checked in order output)
  let elementType='Board';

  // ProductionSite Category (to split the orders for different production sites)
  let elementCategory='';

  // Id of the parent to create the hierarchy
  let parentBomId=part.pa_BomId;

  // Call the function to process the Bom-Element
  GlobalFunc.process_BoardBom(this, part, elementType, elementCategory, parentBomId);

ncData.valueScript:
let drillings: ICT_tab_HardwareDrillVertLibrary[] = [];

// Find all processings for the drawerbox (to each part)
let processings = GlobalFunc.find_ProcessingMapping(part2.pa_ProcessingId2);

// Find the drillings for the sidepanel
processings.forEach((processing) => {
  if(processing.ProcessingLibrary == 'DrillVertical'){
    let foundDrillings = GlobalFunc.find_HardwareDrillVertLibrary(processing.ProcessingId!, 'Front');
    drillings = drillings.concat(foundDrillings);
  } 
});

//====================================================================
// For each drilling (insert the drillings) left box connector
//====================================================================

drillings.forEach(x => 
{  
  // Position of the drill
  let PosX=posRel.x + x.XA;
  let PosY=posRel.y + x.YA;
  let PosZ=0;

  // Add Vertical Drill
  let DrillVert =this.addncout_DrillVert();
  DrillVert.nc_TOOL="102";
  DrillVert.nc_XA=PosX;
  DrillVert.nc_YA = partSelf._dimy - PosY;
  DrillVert.nc_TI=x.TI;
  DrillVert.nc_DU=x.DU;

  DrillVert.nc_BM = x.matrix_BM || "LS"
  DrillVert.nc_WI = x.matrix_WI ?? 0;
  DrillVert.nc_AB = x.matrix_AB ?? 1;
  DrillVert.nc_LA = x.matrix_LA ?? 0;
  DrillVert.nc_MI = x.matrix_MI ?? 0;
  DrillVert.nc_KO = x.matrix_KO || "00";
  DrillVert.nc_Side = "Top";  

  // Add drawing
  let drilling01 = partSelf.add3DElement('Drilling01', DrillVert, PosX, PosY, PosZ, x.DU, x.DU, x.TI );
  drilling01.extrude('<svg><circle cx="' + 0 + '" cy="' + 0 + '" r="' + x.DU/2 + '" /></svg>', 'z');
})

// Get Processing Mapping
  let processingItems = GlobalFunc.find_ProcessingMapping(partSelf.pa_ProcessingId);

  processingItems.forEach((processingItem) => {
    // Components
    if (processingItem.ProcessingLibrary == "Component") { 

      let componentLibrary = GlobalFunc.find_ComponentLibrary(processingItem.ProcessingId!);
      // Add Component
      let component = this.addncout_Component();
      component.nc_TOOL = "139";
      component.nc_IN = componentLibrary.ComponentMPR!;
      component.nc_XA = componentLibrary.XA(partSelf,partSelf)!;
      component.nc_YA = componentLibrary.YA(partSelf,partSelf)!;
      component.nc_ZA = componentLibrary.ZA(partSelf,partSelf)!;
      component.nc_WI = 0;
      component.nc_EM = componentLibrary.EM!;
      component.nc_KAT = componentLibrary.KAT!;
      component.nc_KO = componentLibrary.KO!;
      component.nc_Side = componentLibrary.Side!;

      let variables = GlobalFunc.find_ComponentVariables(componentLibrary.ComponentId!);
      component.nc_VA = "";
      variables.forEach((variable) => {
        let variableValue = variable.VariableValue(partSelf,partSelf)!;
        component.nc_VA += 'VA="' +variable.Variable + ' ' + parseFloat(variableValue.toFixed(2)) + '"' + "\r\n";
      });    
    }

    //else if (processingItem.ProcessingLibrary == "DrillingVertical") {}

    //else if (processingItem.ProcessingLibrary == "DrillingHorizontal") {}





  });
